}

fixed_code:
fn make_op(add: bool) -> Box<dyn Fn(i32) -> i32> {
    if add {
        Box::new(|x| x + 1)
    } else {
        Box::new(|x| x - 1)
    }
}

fn main() {
    let op = make_op(true);
    println!("{}", op(5));
    let op2 = make_op(false);
    println!("{}", op2(5));
}

broken_code:
fn make_greeting(name: &str) -> impl Fn() -> String {
    move || format!("Hello, {}!", name)  // captures `name` which is a &str borrow
}

fn main() {
    let greeting = make_greeting("Alice");
    println!("{}", greeting());
}

fixed_code:
fn make_greeting(name: &str) -> impl Fn() -> String + '_ {
    // Option A: borrow — returned closure tied to caller's lifetime
    move || format!("Hello, {}!", name)
}

// Option B (more flexible): take owned String, return 'static closure
fn make_greeting_owned(name: String) -> impl Fn() -> String {
    move || format!("Hello, {}!", name)
}

fn main() {
    let name = String::from("Alice");
    // Option A: closure tied to `name`'s lifetime
    let greeting = make_greeting(&name);
    println!("{}", greeting());

    // Option B: closure owns the name, can outlive any particular borrow
    let greeting2 = make_greeting_owned(String::from("Bob"));
    println!("{}", greeting2());
}

