fixed_code:
use std::sync::Arc;
use std::thread;

fn make_handler(data: Arc<Vec<i32>>) -> impl Fn() + Send {
    move || {
        println!("{:?}", data);
    }
}

fn main() {
    let data = Arc::new(vec![1, 2, 3]);
    let handler = make_handler(Arc::clone(&data));
    thread::spawn(handler).join().unwrap();
    println!("original data still accessible: {:?}", data);
}

broken_code:
fn make_one_shot(msg: String) -> Box<dyn FnMut() -> String> {
    let mut called = false;
    Box::new(move || {
        if called {
            panic!("closure already consumed!");
        }
        called = true;
        msg.clone()  // forced to clone because FnMut requires &mut self, not consuming self
    })
}

fn main() {
    let mut cb = make_one_shot(String::from("hello"));
    println!("{}", cb());
    println!("{}", cb());  // panics at runtime — should be compile error
}

fixed_code:
fn make_one_shot(msg: String) -> Box<dyn FnOnce() -> String> {
    Box::new(move || msg)  // msg is moved out on call — can only happen once
}

fn main() {
    let cb = make_one_shot(String::from("hello"));
    println!("{}", cb());    // consumes cb
    // println!("{}", cb()); // compile error: use of moved value: `cb`
}
